        "shared_space_library"."libraryId" = "asset"."libraryId"
        and "shared_space_library"."spaceId" = "shared_space_person"."spaceId"
    )
  )
order by
  "asset"."fileCreatedAt" desc,
  "asset_face"."id"
limit
  $7
offset
  $8

-- SharedSpaceRepository.getSpacePersonByIdentity
select
  *
from
