      inner join "asset" on "asset"."id" = "shared_space_asset"."assetId"
    where
      "shared_space_asset"."spaceId" = $1
      and "asset"."deletedAt" is null
      and "asset"."isOffline" = $2
      and "asset"."visibility" in ($3, $4)
    union
